import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/76-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/76-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/76-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 从诸位大人的信件来看，根据来自罗马和曼托瓦的报告，皇帝的备战 正在放缓。但是，按照我自己的观察，可以告诉诸位大人的是，备战正以 更大的力度推进。我在奥格斯堡写信告诉诸位大人，为什么进入曼托瓦境 内的士兵开始撤退，而且威尼斯人在士兵撤退的时候解除了他们的武装， 但随后又把他们重新武装起来。我还写到皇帝准备在这里召开的会议，但 那不是一般的德意志帝国会议，而仅限于蒂罗尔的居民。目的是从他们那 里筹集资金。现在这个会议已经决定提供1000步兵，并由他们支付3个月 的佣金。但是在那之后，当战争真正开始的时候，如果皇帝需要更多士 兵，那他们会再派出5000步兵，并组织10000兵力守卫国家。 步兵和骑兵每天持续到达这里，自从我来到这里，已有大约600或更 多的骑兵经过此地。柯尼斯堡公爵的部队大约有400人，离这里仅有很短 的距离。从我到达这里的时候起，已经有超过2000名步兵途经此地。因 为这个地区十分辽阔，所以我不可能看到或听到所有途经的兵马。先前看起 来可能还不明确，但大批军队可能正迅速从这里输出。某个时间的事态发展 让皇帝来到这里，但今天早上他又离开这里前去视察附近的一些城堡。人们 相信他会在8天之内前往特伦特，那里有步兵、骑兵和炮兵。人人都可以推测 结局将会如何，但结果肯定是以下三种之一：皇帝除了自取其辱之外一无所 获，甚至在奥地利面前都抬不起头来；或者他会攻打意大利；或者会缔结和 平协议。当然，无论如何他都不愿招致羞耻。因此我们必须推测，如果不能 按照其意愿缔结协议，那么他就不得不宣布开战，而那将是很快的事。 我无法推测皇帝对威尼斯人的态度究竟如何。〈兰德里亚诺的首领已 经在28日从威尼斯回到这里，他在那里停留了3天。他到底从那里带回什 么,我实在一无所知。我问过首席大臣，他告诉我说，他也不知道。他还 说，首领跟他见过面，但没有向他透露任何消息。对此，我推测事情可 能不太顺利，特别是我从诸位大人的信中得知，罗马那边事态正在冷淡 下来。我想皇帝应该是没能从罗马得到资金的支持(因为他总是不断要 钱),所以他也许会和威尼斯人达成某种协议。不过，我对此事的看法一",-1),e("p",null,"Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
